      <p className="mb-6 text-sm text-gray-500">Public bookmarks</p>

      <div className="flex w-full max-w-md flex-col gap-3">
        {!bookmarks?.length ? (
          <p className="text-sm text-gray-500">No public bookmarks yet.</p>
