  { value: "private", label: "Private" },
];

type DashboardClientProps = {
  bookmarks: Bookmark[];
};

function filterBookmarks(bookmarks: Bookmark[], filter: Filter) {
  if (filter === "public") {
    return bookmarks.filter((b) => b.is_public);
  }
  if (filter === "private") {
    return bookmarks.filter((b) => !b.is_public);
  }
  return bookmarks;
}

function FilterButton({
  label,
  active,
  onClick,
  className = "",
}: {
  label: string;
  active: boolean;
  onClick: () => void;
  className?: string;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`text-left text-sm transition ${className} ${
        active
          ? "bg-gray-900 text-white"
          : "text-gray-600 hover:bg-gray-100 hover:text-gray-900"
      }`}
    >
      {label}
    </button>
  );
}

