  );
}

function BookmarkCard({
  bookmark,
  editingId,
  onEdit,
  onCancelEdit,
  updateAction,
  deleteAction,
}: BookmarkCardProps) {
  const isEditing = editingId === bookmark.id;

  if (isEditing) {
