            className="rounded border border-gray-300 px-3 py-2"
          />
        </label>

        <label className="flex flex-col gap-1 text-sm">
          URL
          <input
            name="url"
            type="url"
            defaultValue={bookmark.url}
            className="rounded border border-gray-300 px-3 py-2"
          />
        </label>

        <label className="flex items-center gap-2 text-sm">
          <input
            name="is_public"
            type="checkbox"
