            type="button"
            onClick={onCancelEdit}
            className="rounded border border-gray-300 px-3 py-1.5 text-sm"
          >
            Cancel
          </button>
        </div>
      </form>
    );
  }

  return (
    <div className="rounded border border-gray-300 p-4">
