"use client";

import { useActionState, useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import BookmarkList from "@/components/dashboard/bookmark-list";
import FilterPanel, {
  type BookmarkFilter,
} from "@/components/dashboard/filter-panel";
import {
  createBookmark,
  deleteBookmark,
  updateBookmark,
  type BookmarkState,
} from "@/app/dashboard/actions";
import type { Bookmark } from "@/types/bookmark";

const initialState: BookmarkState = {};

type DashboardClientProps = {
  bookmarks: Bookmark[];
};

function filterBookmarks(bookmarks: Bookmark[], filter: BookmarkFilter) {
  if (filter === "public") {
    return bookmarks.filter((b) => b.is_public);
  }
  if (filter === "private") {
    return bookmarks.filter((b) => !b.is_public);
  }
  return bookmarks;
}

export default function DashboardClient({ bookmarks }: DashboardClientProps) {
  const router = useRouter();
  const [filter, setFilter] = useState<BookmarkFilter>("all");
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const filteredBookmarks = useMemo(
    () => filterBookmarks(bookmarks, filter),
    [bookmarks, filter],
  );

  const [createState, createAction, isCreating] = useActionState(
    createBookmark,
    initialState,
  );
  const [updateState, updateAction] = useActionState(
    updateBookmark,
    initialState,
  );
  const [deleteState, deleteAction] = useActionState(
    deleteBookmark,
    initialState,
  );

  useEffect(() => {
    if (createState.success) {
      setShowForm(false);
      router.refresh();
    }
  }, [createState.success, router]);

  useEffect(() => {
    if (updateState.success) {
      setEditingId(null);
      router.refresh();
    }
  }, [updateState.success, router]);

  useEffect(() => {
    if (deleteState.success) {
      router.refresh();
    }
  }, [deleteState.success, router]);

  useEffect(() => {
    if (filter !== "all") {
      setShowForm(false);
    }
  }, [filter]);

  const emptyMessage =
    bookmarks.length === 0
      ? "No bookmarks yet."
      : filter === "public"
        ? "No public bookmarks."
        : filter === "private"
          ? "No private bookmarks."
          : "No bookmarks yet.";

  return (
    <div className="flex flex-1 flex-col md:flex-row">
      <FilterPanel filter={filter} onFilterChange={setFilter} />

      <div className="flex flex-1 flex-col p-6">
        <h1 className="mb-4 text-xl font-medium">Dashboard</h1>

        {filter === "all" ? (
          <>
            <button
              type="button"
              onClick={() => setShowForm((open) => !open)}
              className="w-fit rounded bg-gray-900 px-4 py-2 text-sm text-white"
            >
              Add
            </button>

            {showForm ? (
              <form
                key={createState.success ? "reset" : "active"}
                action={createAction}
                className="mt-4 flex w-full max-w-md flex-col gap-4 rounded border border-gray-300 p-4"
              >
                <label className="flex flex-col gap-1 text-sm">
                  Title
                  <input
